const scan = $input.first().json.body;
const url = scan.url || 'unknown';
const score = scan.score || 0;
const grade = scan.grade || 'F';
const headers = scan.headers || [];

const missingHeaders = headers.filter(h => !h.present);
const passingHeaders = headers.filter(h => h.present);

const missingList = missingHeaders.map(h => `- ${h.header}: ${h.description}`).join('\n');
const passingList = passingHeaders.map(h => `- ${h.header}`).join('\n');

const prompt = `You are a cybersecurity expert. Analyze this website's security header scan and give a concise, friendly report.

Website: ${url}
Security Score: ${score}/100 (Grade: ${grade})

MISSING headers (security risks):
${missingList || 'None'}

PRESENT headers (good):
${passingList || 'None'}

Provide:
1. A 2-sentence plain-English summary of the security risk level
2. Top 3 priority fixes (most critical first) with a one-line explanation of WHY each matters
3. One positive thing if any headers are present

Keep it under 200 words. Be direct and developer-friendly.`;

return [{ json: { prompt, url, score, grade } }];

const claudeResponse = $input.first().json;
const prevData = $('Build Prompt').first().json;

const explanation = claudeResponse.content?.[0]?.text || 'Unable to generate explanation.';

return [{
  json: {
    url: prevData.url,
    score: prevData.score,
    grade: prevData.grade,
    explanation
  }
}];
